const config = $('Set research configuration').first().json;
const toIso = (value) => {
  const text = String(value || '');
  if (/^\d{14}$/.test(text)) return `${text.slice(0, 4)}-${text.slice(4, 6)}-${text.slice(6, 8)}T${text.slice(8, 10)}:${text.slice(10, 12)}:${text.slice(12, 14)}Z`;
  const date = new Date(text); return Number.isNaN(date.valueOf()) ? undefined : date.toISOString();
};
return ($input.first().json.articles || []).filter((article) => article.title && article.url).slice(0, 10).map((article) => ({ json: {
  workspaceId: config.workspaceId,
  title: `GDELT News: ${article.title}`,
  sourceUrl: article.url,
  publishedAt: toIso(article.seendate),
  sourceName: 'GDELT DOC API',
  sourceType: 'report',
  content: `News metadata collected from GDELT. Outlet: ${article.domain || 'not supplied'}. Tone: ${article.tone || 'not supplied'}. Language: ${article.language || 'not supplied'}. Query: ${config.researchQuery}. This is article metadata, not a claim about business performance.`
} }));
